-// Render agent text with basic markdown-like formatting
-function AgentText({ text }: { text: string }) {
-  // Split into lines for processing
-  const lines = text.split("\n");
-  const elements: React.ReactNode[] = [];
-  let currentParagraph: string[] = [];
-  let inCodeBlock = false;
-  let codeBlockContent: string[] = [];
-  let listItems: string[] = [];
-  let listType: "ul" | "ol" | null = null;
-
-  const flushParagraph = () => {
-    if (currentParagraph.length > 0) {
-      const content = currentParagraph.join(" ");
-      elements.push(
-        <p key={elements.length} className="mb-3 leading-relaxed">
-          {renderInlineFormatting(content)}
-        </p>,
-      );
-      currentParagraph = [];
-    }
-  };
-
-  const flushList = () => {
-    if (listItems.length > 0) {
-      const ListTag = listType === "ol" ? "ol" : "ul";
-      elements.push(
-        <ListTag
-          key={elements.length}
-          className={`mb-3 space-y-1 ${listType === "ol" ? "list-decimal" : "list-disc"} pl-5`}
-        >
-          {listItems.map((item, i) => (
-            <li key={i}>{renderInlineFormatting(item)}</li>
-          ))}
-        </ListTag>,
-      );
-      listItems = [];
-      listType = null;
-    }
-  };
-
-  for (const line of lines) {
-    // Code block start/end
-    if (line.startsWith("```")) {
-      if (!inCodeBlock) {
-        flushParagraph();
-        flushList();
-        inCodeBlock = true;
-        codeBlockContent = [];
-      } else {
-        elements.push(
-          <pre key={elements.length} className="mb-3 overflow-x-auto rounded-lg bg-zinc-900 p-4 text-sm">
-            <code>{codeBlockContent.join("\n")}</code>
-          </pre>,
-        );
-        inCodeBlock = false;
-        codeBlockContent = [];
-      }
-      continue;
-    }
-
-    if (inCodeBlock) {
-      codeBlockContent.push(line);
-      continue;
-    }
-
-    // Unordered list item
-    if (line.match(/^[-*]\s+/)) {
-      flushParagraph();
-      if (listType !== "ul") {
-        flushList();
-        listType = "ul";
-      }
-      listItems.push(line.replace(/^[-*]\s+/, ""));
-      continue;
-    }
-
-    // Ordered list item
-    if (line.match(/^\d+\.\s+/)) {
-      flushParagraph();
-      if (listType !== "ol") {
-        flushList();
-        listType = "ol";
-      }
-      listItems.push(line.replace(/^\d+\.\s+/, ""));
-      continue;
-    }
-
-    // Empty line - flush current paragraph
-    if (line.trim() === "") {
-      flushParagraph();
-      flushList();
-      continue;
-    }
-
-    // Regular line - add to current paragraph
-    flushList();
-    currentParagraph.push(line);
-  }
-
-  // Flush remaining content
-  if (inCodeBlock && codeBlockContent.length > 0) {
-    elements.push(
-      <pre key={elements.length} className="mb-3 overflow-x-auto rounded-lg bg-zinc-900 p-4 text-sm">
-        <code>{codeBlockContent.join("\n")}</code>
-      </pre>,
-    );
-  }
-  flushParagraph();
-  flushList();
-
-  return <>{elements}</>;
-}
